from collections import defaultdict

class Solution:
    def maxKDivisibleComponents(self, n, edges, values, k):
        m = len(edges)
        best = 0
        for mask in range(1 << m):
            parent = list(range(n))

            def find(x):
                while parent[x] != x:
                    parent[x] = parent[parent[x]]
                    x = parent[x]
                return x

            for i in range(m):
                if not ((mask >> i) & 1):
                    a, b = edges[i]
                    ra, rb = find(a), find(b)
                    if ra != rb:
                        parent[ra] = rb
            comp_sum = defaultdict(int)
            for node in range(n):
                comp_sum[find(node)] += values[node]
            if all(s % k == 0 for s in comp_sum.values()):
                count = len(comp_sum)
                if count > best:
                    best = count
        return best

