from collections import defaultdict

class Solution:
    def maxKDivisibleComponents(self, n, edges, values, k):
        if n == 1:
            return 1
        adj = defaultdict(list)
        for a, b in edges:
            adj[a].append(b)
            adj[b].append(a)
        parent = [-1] * n
        visited = [False] * n
        order = []
        stack = [0]
        visited[0] = True
        while stack:
            node = stack.pop()
            order.append(node)
            for nb in adj[node]:
                if not visited[nb]:
                    visited[nb] = True
                    parent[nb] = node
                    stack.append(nb)
        total = values[:]
        count = 0
        for node in reversed(order):
            if total[node] % k == 0:
                count += 1
            elif parent[node] != -1:
                total[parent[node]] += total[node]
        return count

